CREATE OR REPLACE FUNCTION public.apply_daily_yield(p_asset_code text, p_daily_yield_percentage numeric, p_application_date date DEFAULT CURRENT_DATE)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_total_aum NUMERIC(28,10) := 0;
  v_total_yield NUMERIC(28,10) := 0;
  v_investors_affected INTEGER := 0;
  v_application_id UUID;
  v_source RECORD;
  v_yield_amount NUMERIC(28,10);
  v_new_balance NUMERIC(28,10);
BEGIN
  IF NOT public.is_admin_v2() THEN
    RAISE EXCEPTION 'Admin access required';
  END IF;

  PERFORM public.recalculate_aum_percentages(p_asset_code);

  SELECT COALESCE(SUM(current_balance), 0) 
  INTO v_total_aum FROM public.yield_sources WHERE asset_code = p_asset_code;

  v_total_yield := v_total_aum * (p_daily_yield_percentage / 100);

  INSERT INTO public.daily_yield_applications (
    application_date, asset_code, total_aum, daily_yield_percentage, total_yield_generated, applied_by
  ) VALUES (
    p_application_date, p_asset_code, v_total_aum, p_daily_yield_percentage, v_total_yield, auth.uid()
  ) RETURNING id INTO v_application_id;

  FOR v_source IN 
    SELECT * FROM public.yield_sources WHERE asset_code = p_asset_code AND current_balance > 0
  LOOP
    v_yield_amount := v_source.current_balance * (p_daily_yield_percentage / 100);
    v_new_balance := v_source.current_balance + v_yield_amount;

    UPDATE public.positions 
    SET current_balance = v_new_balance, total_earned = total_earned + v_yield_amount, updated_at = now()
    WHERE user_id = v_source.user_id AND asset_code = p_asset_code::public.asset_symbol;

    UPDATE public.yield_sources
    SET current_balance = v_new_balance, last_updated = now()
    WHERE id = v_source.id;

    INSERT INTO public.yield_distribution_log (
      application_date, user_id, asset_code, balance_before, yield_amount, 
      balance_after, percentage_owned, daily_yield_application_id
    ) VALUES (
      p_application_date, v_source.user_id, p_asset_code, v_source.current_balance, 
      v_yield_amount, v_new_balance, v_source.percentage_of_aum, v_application_id
    );

    v_investors_affected := v_investors_affected + 1;
  END LOOP;

  UPDATE public.daily_yield_applications
  SET investors_affected = v_investors_affected WHERE id = v_application_id;

  RETURN jsonb_build_object(
    'success', true, 'application_id', v_application_id, 'total_aum', v_total_aum,
    'total_yield_generated', v_total_yield, 'investors_affected', v_investors_affected
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.apply_daily_yield_to_fund(p_fund_id uuid, p_daily_yield_percentage numeric, p_application_date date DEFAULT CURRENT_DATE)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_fund_aum NUMERIC(28,10);
  v_total_yield NUMERIC(28,10);
  v_investors_affected INTEGER := 0;
  v_application_id UUID;
  v_position RECORD;
  v_yield_amount NUMERIC(28,10);
  v_new_value NUMERIC(28,10);
  v_fund_code TEXT;
BEGIN
  IF NOT public.is_admin_v2() THEN
    RAISE EXCEPTION 'Admin access required';
  END IF;

  SELECT f.code, fda.total_aum INTO v_fund_code, v_fund_aum
  FROM public.funds f
  LEFT JOIN public.fund_daily_aum fda ON fda.fund_id = f.id AND fda.aum_date <= p_application_date
  WHERE f.id = p_fund_id ORDER BY fda.aum_date DESC LIMIT 1;

  IF v_fund_aum IS NULL THEN
    RAISE EXCEPTION 'No AUM data found for fund';
  END IF;

  v_total_yield := v_fund_aum * (p_daily_yield_percentage / 100);
  PERFORM public.update_investor_aum_percentages(p_fund_id, v_fund_aum);

  INSERT INTO public.daily_yield_applications (
    application_date, asset_code, total_aum, daily_yield_percentage, total_yield_generated, applied_by
  ) VALUES (
    p_application_date, v_fund_code, v_fund_aum, p_daily_yield_percentage, v_total_yield, auth.uid()
  ) RETURNING id INTO v_application_id;

  FOR v_position IN 
    SELECT * FROM public.investor_positions 
    WHERE fund_id = p_fund_id AND current_value > 0 AND aum_percentage > 0
  LOOP
    v_yield_amount := v_position.current_value * (p_daily_yield_percentage / 100);
    v_new_value := v_position.current_value + v_yield_amount;

    UPDATE public.investor_positions 
    SET current_value = v_new_value, unrealized_pnl = unrealized_pnl + v_yield_amount,
        updated_at = now(), last_modified_by = auth.uid()
    WHERE investor_id = v_position.investor_id AND fund_id = p_fund_id;

    INSERT INTO public.yield_distribution_log (
      application_date, user_id, asset_code, balance_before, yield_amount,
      balance_after, percentage_owned, daily_yield_application_id
    ) VALUES (
      p_application_date, v_position.investor_id, v_fund_code, v_position.current_value,
      v_yield_amount, v_new_value, v_position.aum_percentage, v_application_id
    );

    v_investors_affected := v_investors_affected + 1;
  END LOOP;

  UPDATE public.daily_yield_applications
  SET investors_affected = v_investors_affected WHERE id = v_application_id;

  RETURN jsonb_build_object(
    'success', true, 'application_id', v_application_id, 'fund_aum_native', v_fund_aum,
    'total_yield_generated_native', v_total_yield, 'investors_affected', v_investors_affected,
    'asset_code', v_fund_code
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.apply_daily_yield_with_fees(p_fund_id uuid, p_daily_yield_percentage numeric, p_application_date date DEFAULT CURRENT_DATE)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_fund_aum NUMERIC(28,10);
  v_total_yield NUMERIC(28,10);
  v_total_fees NUMERIC(28,10) := 0;
  v_investors_affected INTEGER := 0;
  v_application_id UUID;
  v_position RECORD;
  v_gross_yield NUMERIC(28,10);
  v_fee_amount NUMERIC(28,10);
  v_net_yield NUMERIC(28,10);
  v_fund_code TEXT;
  v_investor_fee_rate NUMERIC(5,4);
BEGIN
  IF NOT public.is_admin_v2() THEN
    RAISE EXCEPTION 'Admin access required';
  END IF;

  SELECT f.code, fda.total_aum INTO v_fund_code, v_fund_aum
  FROM public.funds f
  LEFT JOIN public.fund_daily_aum fda ON fda.fund_id = f.id AND fda.aum_date <= p_application_date
  WHERE f.id = p_fund_id ORDER BY fda.aum_date DESC LIMIT 1;

  IF v_fund_aum IS NULL THEN
    RAISE EXCEPTION 'No AUM data found for fund';
  END IF;

  v_total_yield := v_fund_aum * (p_daily_yield_percentage / 100);
  PERFORM public.update_investor_aum_percentages(p_fund_id, v_fund_aum);

  INSERT INTO public.daily_yield_applications (
    application_date, asset_code, total_aum, daily_yield_percentage, total_yield_generated, applied_by
  ) VALUES (
    p_application_date, v_fund_code, v_fund_aum, p_daily_yield_percentage, v_total_yield, auth.uid()
  ) RETURNING id INTO v_application_id;

  FOR v_position IN 
    SELECT ip.*, COALESCE(p.fee_percentage, 0.02) as investor_fee_rate
    FROM public.investor_positions ip
    JOIN public.investors i ON i.id = ip.investor_id
    LEFT JOIN public.profiles p ON p.id = i.profile_id
    WHERE ip.fund_id = p_fund_id AND ip.current_value > 0 AND ip.aum_percentage > 0
  LOOP
    v_gross_yield := v_position.current_value * (p_daily_yield_percentage / 100);
    v_fee_amount := v_gross_yield * v_position.investor_fee_rate;
    v_net_yield := v_gross_yield - v_fee_amount;
    v_total_fees := v_total_fees + v_fee_amount;

    UPDATE public.investor_positions 
    SET current_value = current_value + v_net_yield, unrealized_pnl = unrealized_pnl + v_net_yield,
        updated_at = now(), last_modified_by = auth.uid()
    WHERE investor_id = v_position.investor_id AND fund_id = p_fund_id;

    INSERT INTO public.platform_fees_collected (
      investor_id, asset_code, fee_month, gross_yield, fee_rate_percentage, fee_amount, net_yield, created_by
    ) VALUES (
      v_position.investor_id, v_fund_code, DATE_TRUNC('month', p_application_date),
      v_gross_yield, v_position.investor_fee_rate, v_fee_amount, v_net_yield, auth.uid()
    ) ON CONFLICT (investor_id, asset_code, fee_month) 
    DO UPDATE SET
      gross_yield = public.platform_fees_collected.gross_yield + EXCLUDED.gross_yield,
      fee_amount = public.platform_fees_collected.fee_amount + EXCLUDED.fee_amount,
      net_yield = public.platform_fees_collected.net_yield + EXCLUDED.net_yield;

    INSERT INTO public.yield_distribution_log (
      application_date, user_id, asset_code, balance_before, yield_amount,
      balance_after, percentage_owned, daily_yield_application_id
    ) VALUES (
      p_application_date, v_position.investor_id, v_fund_code, v_position.current_value,
      v_net_yield, v_position.current_value + v_net_yield, v_position.aum_percentage, v_application_id
    );

    v_investors_affected := v_investors_affected + 1;
  END LOOP;

  INSERT INTO public.monthly_fee_summary (
    summary_month, asset_code, total_gross_yield, total_fees_collected, total_net_yield, investor_count
  ) VALUES (
    DATE_TRUNC('month', p_application_date), v_fund_code,
    v_total_yield, v_total_fees, v_total_yield - v_total_fees, v_investors_affected
  ) ON CONFLICT (summary_month, asset_code)
  DO UPDATE SET
    total_gross_yield = public.monthly_fee_summary.total_gross_yield + EXCLUDED.total_gross_yield,
    total_fees_collected = public.monthly_fee_summary.total_fees_collected + EXCLUDED.total_fees_collected,
    total_net_yield = public.monthly_fee_summary.total_net_yield + EXCLUDED.total_net_yield;

  UPDATE public.daily_yield_applications
  SET investors_affected = v_investors_affected WHERE id = v_application_id;

  RETURN jsonb_build_object(
    'success', true, 'application_id', v_application_id, 'fund_aum_native', v_fund_aum,
    'total_gross_yield', v_total_yield, 'total_platform_fees', v_total_fees,
    'total_net_yield', v_total_yield - v_total_fees, 'investors_affected', v_investors_affected,
    'asset_code', v_fund_code
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.approve_withdrawal(p_request_id uuid, p_approved_amount numeric DEFAULT NULL::numeric, p_admin_notes text DEFAULT NULL::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_request RECORD;
BEGIN
  SELECT * INTO v_request
  FROM public.withdrawal_requests
  WHERE id = p_request_id;

  IF v_request IS NULL THEN
    RAISE EXCEPTION 'Withdrawal request not found';
  END IF;

  IF v_request.status != 'pending' THEN
    RAISE EXCEPTION 'Can only approve pending requests';
  END IF;

  UPDATE public.withdrawal_requests
  SET
    status = 'approved',
    approved_amount = COALESCE(p_approved_amount, requested_amount),
    approved_by = auth.uid(),
    approved_at = NOW(),
    admin_notes = p_admin_notes,
    updated_at = NOW()
  WHERE id = p_request_id;

  RETURN TRUE;
END;
$function$

CREATE OR REPLACE FUNCTION public.backfill_historical_positions(p_start_date date DEFAULT '2024-06-01'::date, p_end_date date DEFAULT CURRENT_DATE)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_result JSONB;
  v_records_created INTEGER := 0;
  v_date DATE;
  v_user RECORD;
  v_position RECORD;
BEGIN
  -- Only allow admins to run this
  IF NOT is_admin_v2() THEN
    RAISE EXCEPTION 'Admin access required';
  END IF;

  -- Create historical_positions table if not exists
  CREATE TABLE IF NOT EXISTS public.historical_positions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL,
    asset_code TEXT NOT NULL,
    balance_date DATE NOT NULL,
    balance NUMERIC(28,10) NOT NULL DEFAULT 0,
    principal NUMERIC(28,10) NOT NULL DEFAULT 0,
    yield_earned NUMERIC(28,10) NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    created_by UUID DEFAULT auth.uid(),
    UNIQUE(user_id, asset_code, balance_date)
  );

  -- Enable RLS on historical_positions
  ALTER TABLE public.historical_positions ENABLE ROW LEVEL SECURITY;

  -- Create RLS policies for historical_positions
  DROP POLICY IF EXISTS "historical_positions_select_own_or_admin" ON public.historical_positions;
  CREATE POLICY "historical_positions_select_own_or_admin" ON public.historical_positions
    FOR SELECT USING (user_id = auth.uid() OR is_admin_v2());

  DROP POLICY IF EXISTS "historical_positions_insert_admin" ON public.historical_positions;
  CREATE POLICY "historical_positions_insert_admin" ON public.historical_positions
    FOR INSERT WITH CHECK (is_admin_v2());

  DROP POLICY IF EXISTS "historical_positions_update_admin" ON public.historical_positions;
  CREATE POLICY "historical_positions_update_admin" ON public.historical_positions
    FOR UPDATE USING (is_admin_v2()) WITH CHECK (is_admin_v2());

  DROP POLICY IF EXISTS "historical_positions_delete_admin" ON public.historical_positions;
  CREATE POLICY "historical_positions_delete_admin" ON public.historical_positions
    FOR DELETE USING (is_admin_v2());

  -- Backfill historical data based on current positions
  FOR v_user IN 
    SELECT DISTINCT user_id FROM public.positions WHERE current_balance > 0
  LOOP
    FOR v_position IN 
      SELECT * FROM public.positions WHERE user_id = v_user.user_id AND current_balance > 0
    LOOP
      -- Create monthly snapshots from start date to current
      v_date := date_trunc('month', p_start_date)::DATE;

      WHILE v_date <= p_end_date LOOP
        -- Calculate simulated historical balance (simplified model)
        INSERT INTO public.historical_positions (
          user_id,
          asset_code,
          balance_date,
          balance,
          principal,
          yield_earned
        ) VALUES (
          v_user.user_id,
          v_position.asset_code::TEXT,
          v_date,
          v_position.current_balance * (0.8 + (EXTRACT(EPOCH FROM (NOW() - v_date::TIMESTAMPTZ)) / 86400 / 365) * 0.4),
          v_position.principal * 0.9,
          v_position.total_earned * (0.3 + (EXTRACT(EPOCH FROM (NOW() - v_date::TIMESTAMPTZ)) / 86400 / 365) * 0.7)
        )
        ON CONFLICT (user_id, asset_code, balance_date) DO NOTHING;

        IF FOUND THEN
          v_records_created := v_records_created + 1;
        END IF;

        v_date := (v_date + INTERVAL '1 month')::DATE;
      END LOOP;
    END LOOP;
  END LOOP;

  v_result := jsonb_build_object(
    'success', true,
    'records_created', v_records_created,
    'start_date', p_start_date,
    'end_date', p_end_date,
    'message', format('Created %s historical position records', v_records_created)
  );

  RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.calculate_next_run_time(p_frequency report_schedule_frequency, p_day_of_week integer, p_day_of_month integer, p_time_of_day time without time zone, p_timezone text, p_current_time timestamp with time zone DEFAULT now())
 RETURNS timestamp with time zone
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_next_run TIMESTAMPTZ;
  v_base_date DATE;
BEGIN
  v_base_date := (p_current_time AT TIME ZONE p_timezone)::DATE;

  CASE p_frequency
    WHEN 'daily' THEN
      v_next_run := (v_base_date + INTERVAL '1 day' + p_time_of_day) AT TIME ZONE p_timezone;

    WHEN 'weekly' THEN
      -- Calculate next occurrence of specified day of week
      v_next_run := (v_base_date +
                    ((p_day_of_week - EXTRACT(DOW FROM v_base_date)::INTEGER + 7) % 7)::INTEGER * INTERVAL '1 day' +
                    p_time_of_day) AT TIME ZONE p_timezone;
      IF v_next_run <= p_current_time THEN
        v_next_run := v_next_run + INTERVAL '7 days';
      END IF;

    WHEN 'monthly' THEN
      -- Calculate next occurrence of specified day of month
      v_next_run := (DATE_TRUNC('month', v_base_date) + (p_day_of_month - 1) * INTERVAL '1 day' + p_time_of_day) AT TIME ZONE p_timezone;
      IF v_next_run <= p_current_time THEN
        v_next_run := (DATE_TRUNC('month', v_base_date) + INTERVAL '1 month' + (p_day_of_month - 1) * INTERVAL '1 day' + p_time_of_day) AT TIME ZONE p_timezone;
      END IF;

    WHEN 'quarterly' THEN
      -- First day of next quarter
      v_next_run := (DATE_TRUNC('quarter', v_base_date) + INTERVAL '3 months' + p_time_of_day) AT TIME ZONE p_timezone;

    WHEN 'yearly' THEN
      -- First day of next year
      v_next_run := (DATE_TRUNC('year', v_base_date) + INTERVAL '1 year' + p_time_of_day) AT TIME ZONE p_timezone;

    ELSE
      RAISE EXCEPTION 'Invalid frequency: %', p_frequency;
  END CASE;

  RETURN v_next_run;
END;
$function$

CREATE OR REPLACE FUNCTION public.can_withdraw(p_investor_id uuid, p_fund_id uuid, p_amount numeric)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_position RECORD;
  v_fund RECORD;
BEGIN
  SELECT * INTO v_position
  FROM public.investor_positions
  WHERE investor_id = p_investor_id AND fund_id = p_fund_id;

  SELECT * INTO v_fund
  FROM public.funds
  WHERE id = p_fund_id;

  IF v_position IS NULL THEN
    RETURN jsonb_build_object(
      'can_withdraw', false,
      'reason', 'No position found in this fund'
    );
  END IF;

  IF p_amount > v_position.current_value THEN
    RETURN jsonb_build_object(
      'can_withdraw', false,
      'reason', 'Requested amount exceeds current position value',
      'current_value', v_position.current_value,
      'requested_amount', p_amount
    );
  END IF;

  IF v_position.lock_until_date IS NOT NULL AND v_position.lock_until_date > CURRENT_DATE THEN
    RETURN jsonb_build_object(
      'can_withdraw', false,
      'reason', 'Position is locked until ' || v_position.lock_until_date::TEXT,
      'lock_until', v_position.lock_until_date
    );
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.withdrawal_requests
    WHERE investor_id = p_investor_id
      AND fund_id = p_fund_id
      AND status IN ('pending', 'approved', 'processing')
  ) THEN
    RETURN jsonb_build_object(
      'can_withdraw', false,
      'reason', 'There is already a pending withdrawal request for this fund'
    );
  END IF;

  RETURN jsonb_build_object(
    'can_withdraw', true,
    'current_value', v_position.current_value,
    'shares', v_position.shares,
    'lock_until', v_position.lock_until_date
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.cancel_withdrawal_by_admin(p_request_id uuid, p_reason text, p_admin_notes text DEFAULT NULL::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$
DECLARE 
  v_request RECORD;
BEGIN
  -- Ensure admin privileges
  PERFORM public.ensure_admin();

  -- Validate cancellation reason
  IF p_reason IS NULL OR length(trim(p_reason)) = 0 THEN 
    RAISE EXCEPTION 'Cancellation reason is required';
  END IF;

  -- Get request details
  SELECT * INTO v_request 
  FROM public.withdrawal_requests 
  WHERE id = p_request_id;

  IF v_request IS NULL THEN 
    RAISE EXCEPTION 'Withdrawal request not found';
  END IF;

  IF v_request.status NOT IN ('pending', 'approved') THEN 
    RAISE EXCEPTION 'Can only cancel pending or approved requests. Current status: %', v_request.status;
  END IF;

  -- Update request
  UPDATE public.withdrawal_requests
  SET 
    status = 'cancelled',
    cancellation_reason = p_reason,
    cancelled_by = auth.uid(),
    cancelled_at = NOW(),
    admin_notes = COALESCE(p_admin_notes, admin_notes)
  WHERE id = p_request_id;

  -- Log action
  PERFORM public.log_withdrawal_action(
    p_request_id,
    'cancel',
    jsonb_build_object(
      'reason', p_reason,
      'previous_status', v_request.status,
      'admin_notes', p_admin_notes
    )
  );

  RETURN TRUE;
END;
$function$

CREATE OR REPLACE FUNCTION public.create_withdrawal_request_v2(p_investor_id uuid, p_fund_id uuid, p_amount numeric, p_type text DEFAULT 'partial'::text, p_notes text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_request_id UUID;
  v_can_withdraw JSONB;
  v_fund_class TEXT;
BEGIN
  v_can_withdraw = public.can_withdraw(p_investor_id, p_fund_id, p_amount);

  IF NOT (v_can_withdraw->>'can_withdraw')::BOOLEAN THEN
    RAISE EXCEPTION 'Withdrawal not allowed: %', v_can_withdraw->>'reason';
  END IF;

  SELECT fund_class INTO v_fund_class
  FROM public.funds
  WHERE id = p_fund_id;

  INSERT INTO public.withdrawal_requests (
    investor_id,
    fund_id,
    fund_class,
    requested_amount,
    withdrawal_type,
    notes,
    created_by
  ) VALUES (
    p_investor_id,
    p_fund_id,
    v_fund_class,
    p_amount,
    p_type,
    p_notes,
    auth.uid()
  ) RETURNING id INTO v_request_id;

  RETURN v_request_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.decrypt_totp_secret(encrypted_secret bytea)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$
DECLARE
    master_key BYTEA;
    decrypted_secret TEXT;
BEGIN
    -- Get the master key for TOTP encryption
    SELECT secret INTO master_key 
    FROM pgsodium.key 
    WHERE name = 'totp_master_key';

    IF master_key IS NULL THEN
        RAISE EXCEPTION 'TOTP master key not found';
    END IF;

    -- Decrypt the secret
    decrypted_secret := convert_from(
        pgsodium.crypto_aead_det_decrypt(
            encrypted_secret,
            convert_to('totp_secret', 'utf8'),
            master_key
        ),
        'utf8'
    );

    RETURN decrypted_secret;
EXCEPTION
    WHEN OTHERS THEN
        -- Fallback to pgcrypto
        RETURN pgp_sym_decrypt(encrypted_secret, 'totp_master_key_fallback');
END;
$function$

CREATE OR REPLACE FUNCTION public.distribute_monthly_yield(p_fund_id uuid, p_report_month date, p_new_aum numeric, p_admin_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_old_aum numeric;
    v_deposits numeric;
    v_withdrawals numeric;
    v_yield_pot numeric;
    v_investor_record record;
    v_share_ratio numeric;
    v_investor_yield numeric;
    v_investor_new_balance numeric;
    v_count integer := 0;
    v_fund_asset_code text;
BEGIN
    -- Security Check: Ensure caller is a valid admin
    IF NOT EXISTS (
        SELECT 1 FROM public.profiles 
        WHERE id = auth.uid() 
        AND is_admin = true
    ) THEN
        RAISE EXCEPTION 'Access Denied: Only admins can distribute yield.';
    END IF;

    -- A. Get Fund Details
    SELECT total_aum, asset_symbol INTO v_old_aum, v_fund_asset_code
    FROM funds WHERE id = p_fund_id;

    -- B. Get Net Flows for the month
    -- Using inline logic to ensure we use the same secure context
    SELECT 
        COALESCE(SUM(amount) FILTER (WHERE type = 'DEPOSIT'), 0),
        COALESCE(SUM(amount) FILTER (WHERE type = 'WITHDRAWAL'), 0)
    INTO v_deposits, v_withdrawals
    FROM transactions_v2
    WHERE asset = v_fund_asset_code
    AND status = 'completed'
    AND date_trunc('month', occurred_at) = date_trunc('month', p_report_month);

    -- C. Calculate the "Yield Pot"
    v_yield_pot := p_new_aum - (v_old_aum + v_deposits - v_withdrawals);

    -- Safety Check
    IF v_old_aum <= 0 THEN
        RAISE EXCEPTION 'Cannot distribute yield: Previous Fund AUM is 0.';
    END IF;

    -- D. Loop through Active Investors
    FOR v_investor_record IN 
        SELECT * FROM investor_positions 
        WHERE fund_id = p_fund_id AND status = 'active'
    LOOP
        -- 1. Ownership %
        v_share_ratio := v_investor_record.shares / v_old_aum;

        -- 2. Specific yield
        v_investor_yield := v_yield_pot * v_share_ratio;

        -- 3. New Balance
        v_investor_new_balance := v_investor_record.shares + v_investor_yield; 

        -- 4. Update Position
        UPDATE investor_positions
        SET 
            shares = shares + v_investor_yield,
            total_yield_earned = total_yield_earned + v_investor_yield,
            updated_at = now()
        WHERE id = v_investor_record.id;

        -- 5. Create Monthly Report Record
        INSERT INTO investor_monthly_reports (
            investor_id,
            report_month,
            asset_code,
            opening_balance,
            additions, 
            withdrawals,
            yield_earned,
            closing_balance,
            edited_by
        ) VALUES (
            v_investor_record.investor_id,
            p_report_month,
            v_fund_asset_code,
            v_investor_record.shares, 
            0, -- Placeholder: flow query could be added here for precision
            0, -- Placeholder
            v_investor_yield,
            v_investor_new_balance,
            p_admin_id
        )
        ON CONFLICT (investor_id, report_month, asset_code) 
        DO UPDATE SET
            yield_earned = EXCLUDED.yield_earned,
            closing_balance = EXCLUDED.closing_balance,
            updated_at = now();

        v_count := v_count + 1;
    END LOOP;

    -- E. Update Master Fund AUM
    UPDATE funds 
    SET total_aum = p_new_aum, updated_at = now()
    WHERE id = p_fund_id;

    RETURN json_build_object(
        'success', true,
        'yield_distributed', v_yield_pot,
        'investors_updated', v_count,
        'new_aum', p_new_aum
    );
END;
$function$

CREATE OR REPLACE FUNCTION public.encrypt_totp_secret(secret_text text)
 RETURNS bytea
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$
DECLARE
    master_key BYTEA;
    encrypted_secret BYTEA;
BEGIN
    -- Get the master key for TOTP encryption
    SELECT secret INTO master_key 
    FROM pgsodium.key 
    WHERE name = 'totp_master_key';

    IF master_key IS NULL THEN
        RAISE EXCEPTION 'TOTP master key not found';
    END IF;

    -- Encrypt the secret using authenticated encryption
    encrypted_secret := pgsodium.crypto_aead_det_encrypt(
        convert_to(secret_text, 'utf8'),
        convert_to('totp_secret', 'utf8'), -- Additional authenticated data
        master_key
    );

    RETURN encrypted_secret;
EXCEPTION
    WHEN OTHERS THEN
        -- Fallback to pgcrypto if pgsodium fails
        RETURN pgp_sym_encrypt(secret_text, 'totp_master_key_fallback');
END;
$function$

CREATE OR REPLACE FUNCTION public.generate_historical_statements()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$
DECLARE
  v_investor RECORD;
  v_year INTEGER;
  v_month INTEGER;
  v_generated_count INTEGER := 0;
  v_errors JSONB := '[]'::JSONB;
BEGIN
  -- Only allow admins
  PERFORM public.ensure_admin();

  -- Generate statements for the last 6 months
  FOR v_year IN 2024..2025 LOOP
    FOR v_month IN 
      CASE WHEN v_year = 2024 THEN 7 ELSE 1 END..
      CASE WHEN v_year = 2025 THEN 9 ELSE 12 END
    LOOP
      -- Generate for each investor
      FOR v_investor IN 
        SELECT DISTINCT i.id, i.profile_id
        FROM investors i
        JOIN investor_positions ip ON ip.investor_id = i.id
        WHERE ip.current_value > 0
      LOOP
        BEGIN
          INSERT INTO public.statements (
            user_id,
            period_year,
            period_month,
            generated_at,
            data
          ) VALUES (
            v_investor.profile_id,
            v_year,
            v_month,
            now(),
            generate_statement_data(v_investor.id, v_year, v_month)
          )
          ON CONFLICT (user_id, period_year, period_month) DO NOTHING;

          v_generated_count := v_generated_count + 1;

        EXCEPTION WHEN OTHERS THEN
          v_errors := v_errors || jsonb_build_object(
            'investor_id', v_investor.id,
            'year', v_year,
            'month', v_month,
            'error', SQLERRM
          );
        END;
      END LOOP;
    END LOOP;
  END LOOP;

  RETURN jsonb_build_object(
    'success', true,
    'generated_statements', v_generated_count,
    'errors', v_errors
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.is_2fa_required(p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$
DECLARE
    user_is_admin BOOLEAN;
    policy_record RECORD;
    user_totp_record RECORD;
BEGIN
    -- Check if user is admin
    SELECT is_admin INTO user_is_admin 
    FROM profiles 
    WHERE id = p_user_id;

    -- Get current policy
    SELECT * INTO policy_record FROM system_2fa_policy LIMIT 1;

    -- Get user's TOTP settings
    SELECT * INTO user_totp_record 
    FROM user_totp_settings 
    WHERE user_id = p_user_id;

    -- Check if 2FA is required based on policy
    IF user_is_admin AND policy_record.require_2fa_for_admins THEN
        RETURN TRUE;
    END IF;

    IF NOT user_is_admin AND policy_record.require_2fa_for_investors THEN
        RETURN TRUE;
    END IF;

    -- Check if specifically required for this user
    IF user_totp_record.enforce_required THEN
        RETURN TRUE;
    END IF;

    RETURN FALSE;
END;
$function$

