CREATE OR REPLACE FUNCTION public.log_data_edit()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$
DECLARE
  v_import_id UUID;
  v_edit_source TEXT;
  v_record_id TEXT;
BEGIN
  -- Determine edit source
  IF current_setting('app.edit_source', true) IS NOT NULL THEN
    v_edit_source = current_setting('app.edit_source', true);
  ELSE
    v_edit_source = 'manual';
  END IF;

  -- Get import ID if this is import-related
  IF current_setting('app.import_id', true) IS NOT NULL THEN
    v_import_id = current_setting('app.import_id', true)::UUID;
  END IF;

  -- Try to get record ID from common ID fields, fallback to generating one
  BEGIN
    IF TG_OP = 'DELETE' THEN
      v_record_id = COALESCE(
        (OLD.id)::TEXT,
        (OLD.user_id)::TEXT,
        (OLD.portfolio_id)::TEXT,
        gen_random_uuid()::TEXT
      );
    ELSE
      v_record_id = COALESCE(
        (NEW.id)::TEXT,
        (NEW.user_id)::TEXT, 
        (NEW.portfolio_id)::TEXT,
        gen_random_uuid()::TEXT
      );
    END IF;
  EXCEPTION
    WHEN OTHERS THEN
      v_record_id = gen_random_uuid()::TEXT;
  END;

  -- Log the edit only if we can safely do so
  BEGIN
    INSERT INTO public.data_edit_audit (
      table_name,
      record_id,
      operation,
      old_data,
      new_data,
      import_related,
      import_id,
      edited_by,
      edit_source
    ) VALUES (
      TG_TABLE_NAME,
      v_record_id,
      TG_OP,
      CASE WHEN TG_OP != 'INSERT' THEN to_jsonb(OLD) ELSE NULL END,
      CASE WHEN TG_OP != 'DELETE' THEN to_jsonb(NEW) ELSE NULL END,
      v_import_id IS NOT NULL,
      v_import_id,
      auth.uid(),
      v_edit_source
    );
  EXCEPTION
    WHEN OTHERS THEN
      -- If audit logging fails, don't block the operation
      NULL;
  END;

  RETURN COALESCE(NEW, OLD);
END;
$function$

CREATE OR REPLACE FUNCTION public.reject_withdrawal(p_request_id uuid, p_reason text, p_admin_notes text DEFAULT NULL::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$
DECLARE 
  v_request RECORD;
BEGIN
  -- Ensure admin privileges
  PERFORM public.ensure_admin();

  -- Validate rejection reason
  IF p_reason IS NULL OR length(trim(p_reason)) = 0 THEN 
    RAISE EXCEPTION 'Rejection reason is required';
  END IF;

  -- Get request details
  SELECT * INTO v_request 
  FROM public.withdrawal_requests 
  WHERE id = p_request_id;

  IF v_request IS NULL THEN 
    RAISE EXCEPTION 'Withdrawal request not found';
  END IF;

  IF v_request.status != 'pending' THEN 
    RAISE EXCEPTION 'Can only reject pending requests. Current status: %', v_request.status;
  END IF;

  -- Update request
  UPDATE public.withdrawal_requests
  SET 
    status = 'rejected',
    rejection_reason = p_reason,
    rejected_by = auth.uid(),
    rejected_at = NOW(),
    admin_notes = COALESCE(p_admin_notes, admin_notes)
  WHERE id = p_request_id;

  -- Log action
  PERFORM public.log_withdrawal_action(
    p_request_id,
    'reject',
    jsonb_build_object(
      'reason', p_reason,
      'admin_notes', p_admin_notes
    )
  );

  RETURN TRUE;
END;
$function$

CREATE OR REPLACE FUNCTION public.remove_investor_email(investor_uuid uuid, email_to_remove text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  was_primary BOOLEAN;
  email_count INTEGER;
BEGIN
  -- Check if this is the primary email
  SELECT is_primary INTO was_primary
  FROM public.investor_emails
  WHERE investor_id = investor_uuid AND email = email_to_remove;

  -- Count total emails for this investor
  SELECT COUNT(*) INTO email_count
  FROM public.investor_emails
  WHERE investor_id = investor_uuid;

  -- Prevent removing the only email
  IF email_count <= 1 THEN
    RAISE EXCEPTION 'Cannot remove the only email for investor';
  END IF;

  -- Delete the email
  DELETE FROM public.investor_emails
  WHERE investor_id = investor_uuid AND email = email_to_remove;

  -- If we removed the primary, set the oldest remaining email as primary
  IF was_primary THEN
    UPDATE public.investor_emails
    SET is_primary = true
    WHERE id = (
      SELECT id FROM public.investor_emails
      WHERE investor_id = investor_uuid
      ORDER BY created_at ASC
      LIMIT 1
    );
  END IF;

  RETURN true;
END;
$function$

